import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"步步生镰","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/步步生镰.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/步步生镰.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/白刃类/步步生镰.md"};function p(l,a,_,b,i,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"步步生镰",tabindex:"-1"},[s("步步生镰 "),e("a",{class:"header-anchor",href:"#步步生镰","aria-label":'Permalink to "步步生镰"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),o('<h1 id="步步生镰-1" tabindex="-1">步步生镰 <a class="header-anchor" href="#步步生镰-1" aria-label="Permalink to &quot;步步生镰&quot;">​</a></h1><p>步步生镰（技艺）<br> 限制:镰刀/巨镰<br> 想要使用好镰刀那就离不开【转】，以【转】借力，以【转】蓄势，以【转】收刀，以【转】带身动，以自身为锚点，运镰环绕周身，旋如莲绽，一步一生莲。</p><p>莲：D+500<br> 镰旋如莲绽<br> 【莲瓣】:以刀为瓣，如今你的近战触及距离提升3m。<br> 【初绽】:骨朵初开，莲瓣轻绽。在近战攻击时可以同时攻击四个敌方。</p><p>莲：C+1000<br> 限制:拥有莲（D+500）<br> 莲开之日<br> 【莲瓣】:接天莲叶无穷碧。你的近战触及再提升12m。<br> 【莲盛】:映日荷花别样红。你以镰刀进行的近战攻击可以变为以自身为圆心，半径为自身触及的范围攻击。</p><p>一步一生莲（技艺）:C+1000<br> 步步生莲<br> 以标准动作启动，你可以进行一次最远距离为25m的移动，同时攻击你移动路径上所有触及范围内的敌人。</p><p>并蒂莲（技艺）:C+1000<br> 并蒂双生，永结同心<br> 当你进行攻击时，可以选择距离自身4m以内的一位友方单位，该单位为圆心，半径4m的圆内也视为你的攻击范围，每经过一场影片并在其中进行一场战斗后，可选择距离就提升2m。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const f=r(d,[["render",p]]);export{m as __pageData,f as default};
